# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.predicates.Decidability","kind":"class","src_hash":"9cb29084fa4c65c0","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"Decidability()","rhs":"correctly constructs a Decidability instance","over":{"base":"Any"},"name":"Decidability_correct"},"guarantee":"correctly constructs a Decidability instance","fibers":[],"h1":0,"paths":[],"strategy":"refl","details":{},"assumes":[],"trust":["lean.C4.Reduction.ReducesStar.refl"],"compiled":true,"vhash":"1bd00d9cf56ad35a"}
class Decidability(Enum):
    """What proof strategy can verify this predicate?"""
    Z3 = "z3"                    # Pure arithmetic/boolean — Z3 decides
    STRUCTURAL = "structural"    # isinstance, is None, hasattr — pattern match
    LIBRARY = "library"          # Involves library ops — needs library axioms
    ORACLE = "oracle"            # Complex semantic — needs LLM judgment
    UNKNOWN = "unknown"          # Can't determine


