# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.predicates._join_decidability","kind":"function","src_hash":"93fefbc76a9c0fea","in":{"base":"Decidability"},"out":{"base":"Decidability"},"spec":{"lhs":"_join_decidability(a, )","rhs":"least upper bound: the combined predicate is as hard as the harder part","over":{"base":"Decidability"},"name":"_join_decidability_correct","kind":"composition"},"guarantee":"least upper bound: the combined predicate is as hard as the harder part","fibers":[],"h1":0,"paths":[],"strategy":"path_compose","details":{"steps":[{"fn":"get","by":"library_axiom"},{"fn":"get","by":"library_axiom"}]},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"c58bf1bf2e8449f9"}
def _join_decidability(a: Decidability, b: Decidability) -> Decidability:
    """Least upper bound: the combined predicate is as hard as the harder part."""
    order = {Decidability.Z3: 0, Decidability.STRUCTURAL: 1,
             Decidability.LIBRARY: 2, Decidability.ORACLE: 3,
             Decidability.UNKNOWN: 4}
    return a if order.get(a, 4) >= order.get(b, 4) else b


