# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.predicates.parse_predicate","kind":"function","src_hash":"a10539e41a31bfa1","in":{"base":"str"},"out":{"base":"Pred"},"spec":{"lhs":"parse_predicate(sou)","rhs":"parse a python expression string into a pred ast","over":{"base":"str"},"name":"parse_predicate_correct"},"guarantee":"parse a python expression string into a pred ast","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.predicates.parse_predicate_correct","statement":"Path(parse_predicate(x), parse a python expression string into a pred ast)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"2518932f1e3c082d"}
def parse_predicate(source: str) -> Pred:
    """Parse a Python expression string into a Pred AST.

    Supports arbitrary Python expressions including:
    - Arithmetic: x > 0, x + y == z
    - Method calls: x.mean() == 0, xs.count(v) > 0
    - Library calls: sympy.expand(e) == e
    - Logic: x > 0 and x < 100
    - Type tests: isinstance(x, int)
    - Membership: 'key' in d
    - Attribute access: A.shape[0] == A.shape[1]
    - Indexing: d['port'] > 0

    Falls back to a PVar wrapping the raw string on parse failure.
    """
    try:
        tree = python_ast.parse(source, mode='eval')
        return _ast_to_pred(tree.body)
    except (SyntaxError, ValueError, TypeError):
        return PVar(source)


