# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.predicates._z3_check_unsat","kind":"function","src_hash":"3a079ff7dd53a31c","in":{"base":"Pred"},"out":{"base":"Optional[bool]"},"spec":{"lhs":"_z3_check_unsat(pre)","rhs":"check if a predicate is unsatisfiable (empty)","over":{"base":"Pred"},"name":"_z3_check_unsat_correct"},"guarantee":"check if a predicate is unsatisfiable (empty)","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.predicates._z3_check_unsat_correct","statement":"Path(_z3_check_unsat(x), check if a predicate is unsatisfiable (empty))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"0a5c2f2f5f6fcc66"}
def _z3_check_unsat(pred: Pred, var_sorts: Dict[str, str],
                    timeout_ms: int = 3000) -> Optional[bool]:
    """Check if a predicate is unsatisfiable (empty).  Returns True/False/None."""
    if not _HAS_Z3:
        return None
    z3_expr = pred_to_z3(pred, var_sorts)
    if z3_expr is None:
        return None
    try:
        s = Solver()
        s.set('timeout', timeout_ms)
        s.add(z3_expr)
        result = s.check()
        if result == unsat:
            return True
        if result == sat:
            return False
        return None  # timeout
    except Exception:
        return None


