# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.predicates._z3_check_valid","kind":"function","src_hash":"93d50bfb51036bb7","in":{"base":"Pred"},"out":{"base":"bool"},"spec":{"lhs":"_z3_check_valid(pre)","rhs":"check if a predicate is valid (true for all assignments)","over":{"base":"Pred"},"name":"_z3_check_valid_correct"},"guarantee":"check if a predicate is valid (true for all assignments)","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.predicates._z3_check_valid_correct","statement":"Path(_z3_check_valid(x), check if a predicate is valid (true for all assignments))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"9990e50f0e3c8f5f"}
def _z3_check_valid(pred: Pred, var_sorts: Dict[str, str],
                    timeout_ms: int = 3000) -> bool:
    """Check if a predicate is valid (true for all assignments).

    A predicate φ is valid iff ¬φ is unsatisfiable.
    """
    if not _HAS_Z3:
        return False
    z3_expr = pred_to_z3(pred, var_sorts)
    if z3_expr is None:
        return False
    try:
        s = Solver()
        s.set('timeout', timeout_ms)
        s.add(Z3Not(z3_expr))
        result = s.check()
        return result == unsat
    except Exception:
        return False


