# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.predicates.check_cover_exhaustive","kind":"function","src_hash":"e0b8c7bf7a1f2c29","in":{"base":"RefinementCover"},"out":{"base":"Optional[bool]"},"spec":{"lhs":"check_cover_exhaustive(cov)","rhs":"externally check if a cover is exhaustive","over":{"base":"RefinementCover"},"name":"check_cover_exhaustive_correct"},"guarantee":"externally check if a cover is exhaustive","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.predicates.check_cover_exhaustive_correct","statement":"Path(check_cover_exhaustive(x), externally check if a cover is exhaustive)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"738ba5b8bc8ab9f3"}
def check_cover_exhaustive(cover: RefinementCover) -> Optional[bool]:
    """Externally check if a cover is exhaustive.

    Returns True if Z3-proved, False if Z3-refuted, None if unknown.
    """
    all_preds = [f.predicate for f in cover.fibers.values()]
    if not all_preds:
        return False
    disjunction = POr(tuple(all_preds)) if len(all_preds) > 1 else all_preds[0]
    all_vars = {}
    for f in cover.fibers.values():
        all_vars.update(f.variables)
    z3_expr = pred_to_z3(disjunction, all_vars)
    if z3_expr is None:
        return None
    return _z3_check_valid(disjunction, all_vars) or None


