# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.predicates.check_overlap_empty","kind":"function","src_hash":"0942d595fe8af708","in":{"base":"RefinementFiber"},"out":{"base":"Optional[bool]"},"spec":{"lhs":"check_overlap_empty(fib)","rhs":"check if two fibers have empty intersection","over":{"base":"RefinementFiber"},"name":"check_overlap_empty_correct"},"guarantee":"check if two fibers have empty intersection","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.predicates.check_overlap_empty_correct","statement":"Path(check_overlap_empty(x), check if two fibers have empty intersection)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"58b71252296db923"}
def check_overlap_empty(fiber_a: RefinementFiber,
                        fiber_b: RefinementFiber) -> Optional[bool]:
    """Check if two fibers have empty intersection."""
    intersection = PAnd((fiber_a.predicate, fiber_b.predicate))
    all_vars = {**fiber_a.variables, **fiber_b.variables}
    return _z3_check_unsat(intersection, all_vars)


